(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[7816],{1083:(e,t,d)=>{"use strict";d.r(t),d.d(t,{data:()=>a});const a={key:"v-12802acb",path:"/sql/data/insert/",title:"INSERT into",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Syntax",slug:"syntax",children:[]},{level:2,title:"Example One",slug:"example-one",children:[{level:3,title:"Example Two",slug:"example-two",children:[]},{level:3,title:"Example Three",slug:"example-three",children:[]},{level:3,title:"Example Four",slug:"example-four",children:[]}]}],filePathRelative:"sql/data/insert/README.md",git:{updatedTime:162676698e4,contributors:[]}}},8381:(e,t,d)=>{"use strict";d.r(t),d.d(t,{default:()=>o});const a=(0,d(6252).uE)('<h1 id="insert-into" tabindex="-1"><a class="header-anchor" href="#insert-into" aria-hidden="true">#</a> INSERT into</h1><h2 id="syntax" tabindex="-1"><a class="header-anchor" href="#syntax" aria-hidden="true">#</a> Syntax</h2><p>&lt;&lt;&lt; @/code/Insert/insert-usage.sql</p><h2 id="example-one" tabindex="-1"><a class="header-anchor" href="#example-one" aria-hidden="true">#</a> Example One</h2><p>Category : <code>full insert</code><br> Insert these following data to the <code>Employees</code> table.</p><table><thead><tr><th><code>id</code><br>(not <code>PK</code>)</th><th><code>first_name</code></th><th><code>last_name</code></th><th><code>salary</code></th></tr></thead><tbody><tr><td>222</td><td>&#39;Sam&#39;</td><td>&#39;Smith&#39;</td><td>200</td></tr></tbody></table><p>this is how you write it into SQL format</p><p>&lt;&lt;&lt; @/code/Insert/insert-example-one.sql</p><h3 id="example-two" tabindex="-1"><a class="header-anchor" href="#example-two" aria-hidden="true">#</a> Example Two</h3><p>Category : <code>selective insert</code><br> Insert these following data to the <code>Employees</code> table.</p><table><thead><tr><th><code>id</code><br>(<code>PK</code>)</th><th><code>first_name</code></th><th><code>last_name</code></th><th><code>salary</code></th></tr></thead><tbody><tr><td></td><td>&#39;Sam&#39;</td><td>&#39;Smith&#39;</td><td>200</td></tr></tbody></table><p>In this case, you will not insert <code>id</code> attribute by yourself. (because <code>AI</code> constraint) So we have to let that to be blank.</p><p>Now, we have to specify a column to let data to be insert into.</p><p>&lt;&lt;&lt; @/code/Insert/insert-example-two.sql</p><h3 id="example-three" tabindex="-1"><a class="header-anchor" href="#example-three" aria-hidden="true">#</a> Example Three</h3><p>Category : <code>explicit null</code> <code>selective insert</code><br> Insert these following data to the <code>Employees</code> table.</p><table><thead><tr><th><code>id</code><br>(<code>PK</code>)</th><th><code>first_name</code></th><th><code>last_name</code></th><th><code>salary</code></th></tr></thead><tbody><tr><td></td><td>&#39;Sam&#39;</td><td>&#39;Smith&#39;</td><td>200</td></tr><tr><td></td><td>&#39;Jeff&#39;</td><td>&#39;Jeff&#39;</td><td></td></tr></tbody></table><p>In this case, some value is not being specified. We must include something to make the script run.</p><p>We can add <code>Null</code> to the value, as following</p><p>&lt;&lt;&lt; @/code/Insert/insert-example-three.sql</p><h3 id="example-four" tabindex="-1"><a class="header-anchor" href="#example-four" aria-hidden="true">#</a> Example Four</h3><p>Category : <code>implicit null</code> <code>selective insert</code><br> Insert these following data to the <code>Employees</code> table.</p><table><thead><tr><th><code>id</code><br>(<code>PK</code>)</th><th><code>first_name</code></th><th><code>last_name</code></th><th><code>salary</code></th></tr></thead><tbody><tr><td></td><td>&#39;Sam&#39;</td><td>&#39;Smith&#39;</td><td></td></tr><tr><td></td><td>&#39;Jeff&#39;</td><td>&#39;Jeff&#39;</td><td></td></tr></tbody></table><p>In this case, salary is not given but the table have the columns to keep it.</p><p>&lt;&lt;&lt; @/code/Insert/insert-example-three.sql</p><div class="custom-container tip"><p class="custom-container-title">Note</p><p>If not given any value, SQL will set data value to default value. (Null is default of default value)<br> You can set the default value when creating a new table or modifying a column settings.</p></div>',26),o={render:function(e,t){return a}}}}]);